package com.jwebmp.plugins.fontawesome5pro;

import com.google.common.base.Strings;
import com.jwebmp.core.base.angular.client.services.interfaces.AnnotationUtils;
import com.jwebmp.core.base.html.Script;
import com.jwebmp.core.plugins.PluginInformation;
import com.jwebmp.core.services.IPage;
import com.jwebmp.core.services.IPageConfigurator;
import com.jwebmp.webawesome.components.icon.IconFamily;

import java.util.EnumMap;
import java.util.EnumSet;
import java.util.Map;
import java.util.Set;

/**
 * Page configurator for Font Awesome Pro icon packages.
 * <p>
 * Supports two modes:
 * <ul>
 *   <li><strong>Kit mode</strong> — set {@link #setKitCode(String)} with your FA Kit ID.
 *       A {@code <script>} tag is injected into the page head and no SVG icon npm packages are added.
 *       Kit mode also supports custom uploaded icons (fak prefix).</li>
 *   <li><strong>Package mode</strong> — enable individual icon families via {@link #enableFamily(IconFamily)}.
 *       Only the corresponding {@code @fortawesome/pro-*-svg-icons} npm packages are added.</li>
 * </ul>
 */
@PluginInformation(pluginName = "Font Awesome Pro",
        pluginDescription = "Font Awesome Pro icon families for JWebMP. " +
                "Supports Kit-based cloud delivery or selective npm package installation per icon family.",
        pluginUniqueName = "jwebmp-fontawesome-pro",
        pluginVersion = "7.2.0",
        pluginCategories = "fonts, icons, ui, framework",
        pluginSubtitle = "Font Awesome Pro icon support with per-family dependency management.",
        pluginSourceUrl = "https://github.com/GedMarc/JWebMP-FontAwesome5Pro",
        pluginWikiUrl = "https://github.com/GedMarc/JWebMP-FontAwesome5Pro/wiki",
        pluginGitUrl = "https://github.com/GedMarc/JWebMP-FontAwesome5Pro",
        pluginOriginalHomepage = "https://fontawesome.com",
        pluginDownloadUrl = "https://github.com/GedMarc/JWebMP-FontAwesome5Pro")

public class FontAwesome5ProPageConfigurator implements IPageConfigurator<FontAwesome5ProPageConfigurator>
{
    private static final String FA_VERSION = "^7.2.0";

    /**
     * Maps each IconFamily to its npm package name and short alias.
     * Only families that have a corresponding {@code @fortawesome} npm package are included.
     */
    private static final Map<IconFamily, String[]> FAMILY_PACKAGES = new EnumMap<>(IconFamily.class);

    static
    {
        // Pro families — package name, short alias
        FAMILY_PACKAGES.put(IconFamily.Classic,        new String[]{"@fortawesome/pro-solid-svg-icons",          "fontawesome-svg-solid"});
        FAMILY_PACKAGES.put(IconFamily.Duotone,        new String[]{"@fortawesome/pro-duotone-svg-icons",        "fontawesome-svg-duotone"});
        FAMILY_PACKAGES.put(IconFamily.Sharp,          new String[]{"@fortawesome/sharp-solid-svg-icons",        "fontawesome-svg-sharp-solid"});
        FAMILY_PACKAGES.put(IconFamily.Sharp_Duotone,  new String[]{"@fortawesome/sharp-duotone-solid-svg-icons","fontawesome-svg-sharp-duotone-solid"});

        // Pro variants (added as separate families for convenience)
        // These map to the same-variant packages that aren't covered by Classic above
        // Classic covers solid; these cover the other variants
    }

    /**
     * Enabled icon families. Only enabled families will have their npm packages added.
     */
    private static final Set<IconFamily> enabledFamilies = EnumSet.noneOf(IconFamily.class);

    private static String proKey;

    /**
     * The Font Awesome Kit code for cloud-configured icons (including custom uploaded icons).
     * When set, a {@code <script src="https://kit.fontawesome.com/{kitCode}.js">} tag
     * will be added to the page head, and no individual SVG icon packages will be installed.
     */
    private static String kitCode = "";

    /**
     * When true, all Pro variant packages (solid, regular, light, thin, duotone) are added.
     * Use this for convenience when you don't want to enable families individually.
     */
    private static boolean enableAllProVariants = false;

    public FontAwesome5ProPageConfigurator()
    {
        //Nothing Needed
    }

    // ── Configuration ────────────────────────────────────────

    @Override
    public IPage<?> configure(IPage<?> page)
    {
        if (!Strings.isNullOrEmpty(kitCode))
        {
            page.getHead()
                .add(new Script<>("https://kit.fontawesome.com/" + kitCode + ".js")
                        .addAttribute("crossorigin", "anonymous"));
        }
        return page;
    }

    /**
     * Adds Font Awesome Pro SVG icon npm dependencies based on enabled families.
     * Skipped entirely when Kit mode is active.
     */
    @Override
    public IPage<?> configureAngular(IPage<?> page)
    {
        if (!Strings.isNullOrEmpty(kitCode))
        {
            return page;
        }

        if (enableAllProVariants)
        {
            addDependency(page, "@fortawesome/pro-solid-svg-icons",    "fontawesome-svg-solid",    true);
            addDependency(page, "@fortawesome/pro-regular-svg-icons",  "fontawesome-svg-regular",  false);
            addDependency(page, "@fortawesome/pro-light-svg-icons",    "fontawesome-svg-light",    false);
            addDependency(page, "@fortawesome/pro-thin-svg-icons",     "fontawesome-svg-thin",     false);
            addDependency(page, "@fortawesome/pro-duotone-svg-icons",  "fontawesome-svg-duotone",  false);
        }
        else
        {
            for (IconFamily family : enabledFamilies)
            {
                String[] pkg = FAMILY_PACKAGES.get(family);
                if (pkg != null)
                {
                    addDependency(page, pkg[0], pkg[1], family == IconFamily.Classic);
                }
            }
        }

        return page;
    }

    private void addDependency(IPage<?> page, String packageName, String alias, boolean overrides)
    {
        page.getBody().addConfiguration(
                AnnotationUtils.getTsDependency(packageName, FA_VERSION, alias, overrides));
    }

    // ── Lifecycle ────────────────────────────────────────────

    @Override
    public boolean enabled()
    {
        return true;
    }

    @Override
    public Integer sortOrder()
    {
        return 50;
    }

    // ── Family flags ─────────────────────────────────────────

    /**
     * Enables an icon family so its npm package will be added as a dependency.
     * Has no effect when Kit mode is active.
     *
     * @param family the icon family to enable
     */
    public static void enableFamily(IconFamily family)
    {
        enabledFamilies.add(family);
    }

    /**
     * Disables an icon family so its npm package will not be added.
     *
     * @param family the icon family to disable
     */
    public static void disableFamily(IconFamily family)
    {
        enabledFamilies.remove(family);
    }

    /**
     * Returns whether the given icon family is enabled.
     */
    public static boolean isFamilyEnabled(IconFamily family)
    {
        return enabledFamilies.contains(family);
    }

    /**
     * Returns the set of currently enabled icon families.
     */
    public static Set<IconFamily> getEnabledFamilies()
    {
        return EnumSet.copyOf(enabledFamilies);
    }

    // ── Kit code ─────────────────────────────────────────────

    public static String getKitCode()
    {
        return kitCode;
    }

    /**
     * Sets the Font Awesome Kit code. When set, the kit script tag will be
     * injected into the page head and individual SVG icon packages will NOT
     * be added — the Kit script fetches all icons from the cloud.
     * Also enables custom uploaded icons (fak prefix).
     *
     * @param kitCode the kit identifier, e.g. "cf4534f35c"
     */
    public static void setKitCode(String kitCode)
    {
        FontAwesome5ProPageConfigurator.kitCode = kitCode;
    }

    // ── Pro key ──────────────────────────────────────────────

    public static String getProKey()
    {
        return proKey;
    }

    public static void setProKey(String proKey)
    {
        FontAwesome5ProPageConfigurator.proKey = proKey;
    }

    // ── Convenience ──────────────────────────────────────────

    public static boolean isEnableAllProVariants()
    {
        return enableAllProVariants;
    }

    /**
     * When set to true, all five Pro variant packages (solid, regular, light, thin, duotone)
     * are added regardless of individual family flags. Has no effect when Kit mode is active.
     */
    public static void setEnableAllProVariants(boolean enableAll)
    {
        FontAwesome5ProPageConfigurator.enableAllProVariants = enableAll;
    }
}

package com.jwebmp.website.pages;

import com.jwebmp.core.base.angular.client.annotations.angular.NgComponent;
import com.jwebmp.core.base.angular.client.annotations.routing.NgRoutable;
import com.jwebmp.core.base.angular.client.services.interfaces.INgComponent;
import com.jwebmp.webawesome.components.PageSize;
import com.jwebmp.webawesome.components.Variant;
import com.jwebmp.webawesome.components.WaCluster;
import com.jwebmp.webawesome.components.WaStack;
import com.jwebmp.webawesome.components.button.Appearance;

/**
 * Landing page for the JWebMP website.
 * <p>
 * Concise hero, key value propositions, plugin highlights, and CTAs.
 * Detailed technical content lives on the About page.
 */
@NgComponent("jwebmp-home")
@NgRoutable(path = "home", isDefault = true)
public class HomePage extends WebsitePage<HomePage> implements INgComponent<HomePage>
{
    public HomePage()
    {
        var layout = new WaStack();
        layout.setGap(PageSize.ExtraLarge);

        layout.add(buildHero());
        layout.add(buildHighlights());
        layout.add(buildComponentEcosystem());
        layout.add(buildCallToAction());

        getMain().add(layout);
    }

    // ────────────────────────────────────────────────────────

    private WaStack buildHero()
    {
        var hero = new WaStack();
        hero.setGap(PageSize.Large);
        hero.setID("hero");
        hero.addClass("hero-banner");

        // Eyebrow
        var eyebrow = captionText("FULL-STACK JAVA WEB FRAMEWORK");
        eyebrow.addClass("hero-eyebrow");
        hero.add(eyebrow);

        // Main heading — extra large for impact
        var heading = headingText("h1", "xl", "Write Java. Ship Web Apps.");
        heading.addClass("hero-heading");
        hero.add(heading);

        // Subtitle
        var subtitle = bodyText(
                "Build complete web applications in pure Java. JWebMP generates Angular 21 SPAs "
                + "from annotated Java classes — or renders server-side on Vert.x 5. "
                + "One language. Two modes. Zero TypeScript.",
                "l");
        subtitle.setWaColorText("quiet");
        subtitle.addClass("hero-subtitle");
        hero.add(subtitle);

        // Technology tags
        var tags = new WaCluster<>();
        tags.setGap(PageSize.Small);
        tags.addClass("hero-tags");
        tags.add(buildTag("Java 25+", Variant.Brand));
        tags.add(buildTag("Angular 21", Variant.Danger));
        tags.add(buildTag("Vert.x 5", Variant.Warning));
        tags.add(buildTag("JPMS", Variant.Success));
        tags.add(buildTag("20+ Plugins", Variant.Neutral));
        hero.add(tags);

        // Call-to-action buttons
        var ctas = new WaCluster<>();
        ctas.setGap(PageSize.Small);
        ctas.addClass("hero-ctas");
        ctas.add(buildCta("Get Started", "/getting-started", Variant.Brand, null));
        ctas.add(buildCta("About JWebMP", "/about", Variant.Neutral, Appearance.Outlined));
        ctas.add(buildCta("Browse Plugins", "/plugins", Variant.Neutral, Appearance.Outlined));
        hero.add(ctas);

        return hero;
    }

    private WaStack buildHighlights()
    {
        var content = new WaStack();
        content.setGap(PageSize.Medium);

        var grid = grid(3);

        grid.add(featureCard("Annotation-Driven",
                "Annotate your Java classes and the "
                + "build generates a complete Angular 21 project. No hand-written TypeScript.",
                null));

        grid.add(featureCard("Compile-Time Safe",
                "Every HTML element, CSS property, and event handler is a Java type. "
                + "Errors are caught by the compiler, not discovered in the browser.",
                null));

        grid.add(featureCard("Dual Mode",
                "Add the Angular plugin for a generated SPA, or run without it for "
                + "server-side rendering on Vert.x 5. Same component code either way.",
                null));

        grid.add(featureCard("Reactive & Non-Blocking",
                "Built on Vert.x 5 event-loop server and GuicedEE dependency injection. "
                + "JPMS modular, JLink-ready, production-grade.",
                null));

        grid.add(featureCard("Real-Time Ready",
                "REST, AJAX events, Vert.x event bus, and RabbitMQ — start with request/response, "
                + "layer in push updates when you need them.",
                null));

        grid.add(featureCard("IDE-Friendly",
                "Concrete Java classes with full autocomplete, refactoring, find-usages, "
                + "and go-to-definition in IntelliJ, Eclipse, or VS Code.",
                null));

        content.add(grid);

        var section = buildSection("WHY JWEBMP",
                "Everything You Need, Nothing You Don't",
                "A complete web framework that respects Java developers.",
                true, content);
        section.setID("why-jwebmp");
        return section;
    }

    private WaStack buildComponentEcosystem()
    {
        var content = new WaStack();
        content.setGap(PageSize.Medium);

        content.add(bodyText(
                "Every plugin is a JPMS module. Add the Maven dependency, and the component is available as a "
                + "type-safe Java class. Some plugins work in both modes; others — like AG Grid and AG Charts "
                + "— require the Angular plugin.",
                "m"));

        var grid = grid(3);

        grid.add(featureCard("AG Grid & AG Charts",
                "Enterprise data grids and 38+ chart types — configured in Java, rendered in Angular.",
                "com.jwebmp.plugins:aggrid / agcharts"));

        grid.add(featureCard("WebAwesome",
                "Modern, accessible UI component library with dark mode, responsive layout, and 18+ components.",
                "com.jwebmp.plugins:web-awesome"));

        grid.add(featureCard("FullCalendar",
                "Drag-and-drop scheduling, resource timelines, and multiple calendar views.",
                "com.jwebmp.plugins:fullcalendar"));

        grid.add(featureCard("RabbitMQ Comms",
                "Bidirectional messaging with broker-backed durability. STOMP/WebSocket bridge for Angular.",
                "com.jwebmp:jwebmp-rabbitmq"));

        grid.add(featureCard("Font Awesome",
                "6,000+ icons (Free) or 10,000+ (Pro) rendered as SVG with type-safe Java enums.",
                "com.jwebmp.plugins:fontawesome"));

        grid.add(featureCard("Chart.js",
                "Lightweight charts — bar, line, pie, doughnut, radar — for dashboards and reports.",
                "com.jwebmp.plugins:chartjs"));

        content.add(grid);

        var ctas = new WaCluster<>();
        ctas.setGap(PageSize.Small);
        ctas.add(buildCta("Full Plugin Catalog", "/plugins", Variant.Brand, null));
        content.add(ctas);

        var section = buildSection("20+ PLUGINS",
                "Production-Ready Component Library",
                "Grids, charts, calendars, icons, messaging — all type-safe, all Java, all JPMS.",
                true, content);
        section.setID("component-ecosystem");
        return section;
    }

}

package com.jwebmp.website.pages;

import com.jwebmp.core.base.angular.client.annotations.angular.NgComponent;
import com.jwebmp.core.base.angular.client.annotations.routing.NgRoutable;
import com.jwebmp.core.base.angular.client.services.interfaces.INgComponent;
import com.jwebmp.webawesome.components.PageSize;
import com.jwebmp.webawesome.components.Variant;
import com.jwebmp.webawesome.components.WaCluster;
import com.jwebmp.webawesome.components.WaStack;
import com.jwebmp.webawesome.components.button.Appearance;

/**
 * Landing page for the JWebMP website.
 * <p>
 * Concise hero, key value propositions, plugin highlights, and CTAs.
 * Detailed technical content lives on the About page.
 */
@NgComponent("jwebmp-home")
@NgRoutable(path = "home", isDefault = true)
public class HomePage extends WebsitePage<HomePage> implements INgComponent<HomePage>
{
    public HomePage()
    {
        removeClass("website-content");

        var layout = new WaStack();
        layout.setGap(PageSize.ExtraLarge);

        layout.add(buildHero());
        layout.add(buildHighlights());
        layout.add(buildComponentEcosystem());
        layout.add(buildCallToAction());

        getMain().add(layout);
    }

    // ────────────────────────────────────────────────────────

    private WaStack buildHero()
    {
        var hero = new WaStack();
        hero.setGap(PageSize.Large);
        hero.setID("hero");
        hero.addClass("hero-banner");

        // Eyebrow
        var eyebrow = captionText("FULL-STACK JAVA WEB FRAMEWORK");
        eyebrow.addClass("hero-eyebrow");
        hero.add(eyebrow);

        // Main heading — extra large for impact
        var heading = headingText("h1", "xl", "Write Java. Ship Web Apps.");
        heading.addClass("hero-heading");
        hero.add(heading);

        // Subtitle
        var subtitle = bodyText(
                "Build complete web applications in pure Java. JWebMP generates Angular 21 SPAs "
                + "from annotated Java classes — or renders server-side on Vert.x 5. "
                + "One language. Two modes. Zero TypeScript.",
                "l");
        subtitle.setWaColorText("quiet");
        subtitle.addClass("hero-subtitle");
        hero.add(subtitle);

        // Technology tags
        var tags = new WaCluster<>();
        tags.setGap(PageSize.Small);
        tags.addClass("hero-tags");
        tags.add(buildTag("Java 25+", Variant.Brand));
        tags.add(buildTag("Angular 21", Variant.Danger));
        tags.add(buildTag("Vert.x 5", Variant.Warning));
        tags.add(buildTag("JPMS", Variant.Success));
        tags.add(buildTag("20+ Plugins", Variant.Neutral));
        hero.add(tags);

        // Call-to-action buttons
        var ctas = new WaCluster<>();
        ctas.setGap(PageSize.Small);
        ctas.addClass("hero-ctas");
        ctas.add(buildCta("Get Started", "/getting-started", Variant.Brand, null));
        ctas.add(buildCta("About JWebMP", "/about", Variant.Neutral, Appearance.Outlined));
        ctas.add(buildCta("Browse Plugins", "/plugins", Variant.Neutral, Appearance.Outlined));
        hero.add(ctas);

        return hero;
    }

    private WaStack buildHighlights()
    {
        var content = new WaStack();
        content.setGap(PageSize.Medium);

        var grid = grid(3);

        grid.add(featureCard("Annotation-Driven",
                "Annotate your Java classes and the "
                + "build generates a complete Angular 21 project. No hand-written TypeScript.",
                null));

        grid.add(featureCard("Compile-Time Safe",
                "Every HTML element, CSS property, and event handler is a Java type. "
                + "Errors are caught by the compiler, not discovered in the browser.",
                null));

        grid.add(featureCard("Dual Mode",
                "Add the Angular plugin for a generated SPA, or run without it for "
                + "server-side rendering on Vert.x 5. Same component code either way.",
                null));

        grid.add(featureCard("Reactive & Non-Blocking",
                "Built on Vert.x 5 event-loop server and GuicedEE dependency injection. "
                + "JPMS modular, JLink-ready, production-grade.",
                null));

        grid.add(featureCard("Real-Time Ready",
                "REST, AJAX events, Vert.x event bus, and RabbitMQ — start with request/response, "
                + "layer in push updates when you need them.",
                null));

        grid.add(featureCard("IDE-Friendly",
                "Concrete Java classes with full autocomplete, refactoring, find-usages, "
                + "and go-to-definition in IntelliJ, Eclipse, or VS Code.",
                null));

        content.add(grid);

        var section = buildSection("WHY JWEBMP",
                "Everything You Need, Nothing You Don't",
                "A complete web framework that respects Java developers.",
                true, content);
        section.setID("why-jwebmp");
        return section;
    }

    private WaStack buildComponentEcosystem()
    {
        var content = new WaStack();
        content.setGap(PageSize.Medium);

        content.add(bodyText(
                "Every plugin is a JPMS module. Add the Maven dependency, and the component is available as a "
                + "type-safe Java class. Some plugins work in both modes; others — like AG Grid and AG Charts "
                + "— require the Angular plugin.",
                "m"));

        var grid = grid(3);

        grid.add(featureCard("AG Grid & AG Charts",
                "Enterprise data grids and 38+ chart types — configured in Java, rendered in Angular.",
                "com.jwebmp.plugins:aggrid / agcharts"));

        grid.add(featureCard("WebAwesome",
                "Modern, accessible UI component library with dark mode, responsive layout, and 18+ components.",
                "com.jwebmp.plugins:web-awesome"));

        grid.add(featureCard("FullCalendar",
                "Drag-and-drop scheduling, resource timelines, and multiple calendar views.",
                "com.jwebmp.plugins:fullcalendar"));

        grid.add(featureCard("RabbitMQ Comms",
                "Bidirectional messaging with broker-backed durability. STOMP/WebSocket bridge for Angular.",
                "com.jwebmp:jwebmp-rabbitmq"));

        grid.add(featureCard("Font Awesome",
                "6,000+ icons (Free) or 10,000+ (Pro) rendered as SVG with type-safe Java enums.",
                "com.jwebmp.plugins:fontawesome"));

        grid.add(featureCard("Chart.js",
                "Lightweight charts — bar, line, pie, doughnut, radar — for dashboards and reports.",
                "com.jwebmp.plugins:chartjs"));

        content.add(grid);

        var ctas = new WaCluster<>();
        ctas.setGap(PageSize.Small);
        ctas.add(buildCta("Full Plugin Catalog", "/plugins", Variant.Brand, null));
        content.add(ctas);

        var section = buildSection("20+ PLUGINS",
                "Production-Ready Component Library",
                "Grids, charts, calendars, icons, messaging — all type-safe, all Java, all JPMS.",
                true, content);
        section.setID("component-ecosystem");
        return section;
    }

}

package com.jwebmp.plugins.markdown.config;

import com.jwebmp.core.base.angular.client.annotations.angularconfig.NgScript;
import com.jwebmp.core.base.angular.client.annotations.boot.NgBootImportProvider;
import com.jwebmp.core.base.angular.client.annotations.boot.NgBootImportReference;
import com.jwebmp.core.base.angular.client.annotations.typescript.TsDependency;
import com.jwebmp.core.base.angular.client.annotations.typescript.TsDevDependency;
import com.jwebmp.core.plugins.PluginInformation;
import com.jwebmp.core.plugins.PluginStatus;
import com.jwebmp.core.services.IPage;
import com.jwebmp.core.services.IPageConfigurator;
import jakarta.validation.constraints.NotNull;

/**
 * Page configurator for the NGX Markdown plugin.
 * <p>
 * Registers the necessary TypeScript dependencies (ngx-markdown, marked, prismjs, mermaid, katex,
 * emoji-toolkit, clipboard) and configures the Angular module providers required for markdown rendering.
 * </p>
 * <p>
 * The ngx-markdown library combines:
 * <ul>
 *   <li><b>Marked</b> — to parse markdown to HTML</li>
 *   <li><b>PrismJS</b> — for language syntax highlighting</li>
 *   <li><b>Mermaid</b> — for diagrams and charts visualization</li>
 *   <li><b>KaTeX</b> — for math expression rendering</li>
 *   <li><b>Emoji-Toolkit</b> — for emoji support</li>
 *   <li><b>Clipboard.js</b> — to copy code blocks to clipboard</li>
 * </ul>
 * <p>
 * This configurator is automatically discovered via the Java ServiceLoader mechanism
 * through the {@code META-INF/services/com.jwebmp.core.services.IPageConfigurator} file.
 * </p>
 */
@PluginInformation(
        pluginName = "NGX Markdown",
        pluginUniqueName = "ngx-markdown",
        pluginDescription = "Angular markdown component/directive/pipe with Prism.js syntax highlighting, " +
                "Mermaid diagrams, KaTeX math rendering, emoji support, and clipboard copy. " +
                "Built on the ngx-markdown library by jfcere.",
        pluginVersion = "19.0.0",
        pluginCategories = "markdown, syntax highlighting, diagrams, mermaid, katex, emoji",
        pluginSubtitle = "Full-featured Markdown rendering for Angular with syntax highlighting, " +
                "diagrams, math expressions, and emoji — integrated into JWebMP.",
        pluginGitUrl = "https://github.com/JWebMP/Plugins/Markdown",
        pluginWikiUrl = "https://github.com/JWebMP/Plugins/Markdown/wiki",
        pluginOriginalHomepage = "https://github.com/jfcere/ngx-markdown",
        pluginDownloadUrl = "https://mvnrepository.com/artifact/com.jwebmp.plugins/ngx-markdown",
        pluginIconUrl = "",
        pluginIconImageUrl = "",
        pluginLastUpdatedDate = "2026/03/25",
        pluginGroupId = "com.jwebmp.plugins",
        pluginArtifactId = "ngx-markdown",
        pluginModuleName = "com.jwebmp.plugins.markdown",
        pluginStatus = PluginStatus.DevelopmentStarted
)

// Core dependencies
@TsDependency(value = "ngx-markdown", version = "^20.1.0")
@TsDependency(value = "marked", version = "^16.0.0")

// Syntax highlighting (PrismJS) — ngx-markdown uses prismjs directly for highlighting
// The prism plugin also declares this dependency; npm deduplicates to a single version
@TsDependency(value = "prismjs", version = "^1.30.0")
@TsDevDependency(value = "@types/prismjs", version = "^1.26.0")

// Diagrams
@TsDependency(value = "mermaid", version = "^11.13.0")

// Math rendering
@TsDependency(value = "katex", version = "^0.16.0")
@TsDevDependency(value = "@types/katex", version = "^0.16.0")

// Emoji support
@TsDependency(value = "emoji-toolkit", version = "^10.0.0")

// Clipboard support
@TsDependency(value = "clipboard", version = "^2.0.11")
@NgScript(value = "node_modules/clipboard/dist/clipboard.min.js", name = "Clipboard")

// Angular bootstrap: provideMarkdown()
@NgBootImportProvider("provideMarkdown()")
@NgBootImportReference(value = "provideMarkdown", reference = "ngx-markdown")
public class MarkdownPageConfigurator implements IPageConfigurator<MarkdownPageConfigurator>
{
    /**
     * Whether the NGX Markdown plugin is enabled.
     */
    public static boolean enabled = true;

    /**
     * Creates a new MarkdownPageConfigurator instance.
     */
    public MarkdownPageConfigurator()
    {
        // Nothing needed
    }

    @NotNull
    @Override
    public IPage<?> configure(IPage<?> page)
    {
        return page;
    }

    @Override
    public boolean enabled()
    {
        return enabled;
    }
}

